import { Instagram } from "lucide-react"

export default function Footer() {
  return (
    <footer className="bg-primary text-primary-foreground py-16 px-4">
      <div className="mx-auto max-w-7xl">
        <div className="flex flex-col items-center text-center">
          <h3 className="font-serif text-3xl font-medium mb-2">Makkani Restaurant</h3>
          <p className="text-sm tracking-wider text-primary-foreground/80 mb-8">We Serve You Happiness</p>

          <div className="mb-8">
            <a
              href="https://instagram.com"
              target="_blank"
              rel="noopener noreferrer"
              className="flex h-10 w-10 items-center justify-center rounded-full bg-primary-foreground/10 transition-colors hover:bg-accent"
              aria-label="Follow us on Instagram"
            >
              <Instagram className="h-5 w-5" />
            </a>
          </div>

          <div className="h-px w-24 bg-primary-foreground/20 mb-6" />

          <p className="text-sm text-primary-foreground/60">
            © {new Date().getFullYear()} Makkani Restaurant. All rights reserved.
          </p>
        </div>
      </div>
    </footer>
  )
}
